mapper.select:
SELECT PARAM_NO, ITEM_NO, ITEM_ID, ALIAS_NAME, CALCU_ORDER, PRICISION,
       CARRY_BIT, CPNY_ID, CPNY_NAME, APPLY_TYPE, APPLY_TYPE_NAME,
       SHOW_YN, SHOW_ORDER, ITEM_FLAG, ITEM_NUMBER
FROM (
    SELECT a.*, ROWNUM AS RN
    FROM (


        ORDER BY CALCU_ORDER
    ) a
    WHERE ROWNUM <= #{start, jdbcType=NUMERIC} + #{length, jdbcType=NUMERIC}
)
WHERE RN > #{start, jdbcType=NUMERIC}

SELECT PARAM_NO, CALCU_ORDER
  FROM PA_ITEM_PARAM
 WHERE CPNY_ID = #{cpnyId, jdbcType=VARCHAR}
   AND CALCU_ORDER = (


               SELECT MAX(CALCU_ORDER) FROM PA_ITEM_PARAM
                WHERE CPNY_ID = #{cpnyId, jdbcType=VARCHAR}
                  AND CALCU_ORDER < #{currentOrder, jdbcType=NUMERIC}


               SELECT MIN(CALCU_ORDER) FROM PA_ITEM_PARAM
                WHERE CPNY_ID = #{cpnyId, jdbcType=VARCHAR}
                  AND CALCU_ORDER > #{currentOrder, jdbcType=NUMERIC}


   )
